import { extractString } from '../../utils/extract.js';
import { handleError } from '../error.js';
export const createServerUploadItemRouteHandler = (group) => async ({ req, res, localize, ctx }) => {
    if (!group.uploadHandler) {
        res.status(404).end();
        return;
    }
    const key = extractString(req.headers['sonolus-upload-key']);
    if (key === undefined) {
        res.status(400).end();
        return;
    }
    const files = req.files;
    if (!Array.isArray(files)) {
        res.status(400).end();
        return;
    }
    const response = await group.uploadHandler({ ...ctx, key, files });
    if (handleError(response, res, localize))
        return;
    res.json(response);
};
